bool
do_work_end(const DispatchTable &dt, Args &args)
{
    uint64_t workid, threadid;
    if (!args.pop(workid, 0) || !args.pop(threadid, 0))
        return false;

    (*dt.m5_work_end)(workid, threadid);

    return true;
}

Command workend = {
    "workend", 0, 2, do_work_end, "[workid [threadid]]\n"
        "        Exit immediately" };

} // anonymous namespace

